MODULE MY_MODULE
IMPLICIT NONE
PRIVATE
PUBLIC :: TEST_TYPE, TEST_PROC

TYPE, ABSTRACT :: BASE_TYPE
CONTAINS
    PROCEDURE(DEFERRED_PROC), DEFERRED :: DO_SOMETHING
END TYPE BASE_TYPE

ABSTRACT INTERFACE
    SUBROUTINE DEFERRED_PROC(X)
        INTEGER, INTENT(INOUT) :: X
    END SUBROUTINE DEFERRED_PROC
END INTERFACE

TYPE, EXTENDS(BASE_TYPE) :: TEST_TYPE
    INTEGER :: VALUE
CONTAINS
    PROCEDURE :: DO_SOMETHING => IMPL_PROC
    FINAL :: FINALIZE_TEST
END TYPE TEST_TYPE

INTERFACE TEST_PROC
    MODULE PROCEDURE IMPL_PROC
END INTERFACE

CONTAINS

PURE SUBROUTINE IMPL_PROC(X)
    INTEGER, INTENT(INOUT) :: X
    X = X + 1
END SUBROUTINE IMPL_PROC

ELEMENTAL FUNCTION DOUBLE_VAL(Y) RESULT(RES)
    INTEGER, INTENT(IN) :: Y
    INTEGER :: RES
    RES = Y * 2
END FUNCTION DOUBLE_VAL

RECURSIVE FUNCTION FACT(N) RESULT(RES)
    INTEGER, INTENT(IN) :: N
    INTEGER :: RES
    IF (N <= 1) THEN
        RES = 1
    ELSE
        RES = N * FACT(N-1)
    END IF
END FUNCTION FACT

END MODULE MY_MODULE


PROGRAM KEYWORD_ZOO
USE MY_MODULE, ONLY: FACT
USE, INTRINSIC :: ISO_C_BINDING
IMPLICIT NONE

INTEGER, PARAMETER :: N = 5
INTEGER :: I, J
REAL, ALLOCATABLE :: ARR(:)
LOGICAL :: FLAG
CHARACTER(LEN=10) :: STR
COMPLEX :: CMPLX

INTEGER :: ENDIF, IF, ELSEIF
INTEGER, DIMENSION(2) :: FUNCTION
ENDIF = 3; IF = 2

TYPE(TEST_TYPE) :: OBJ
CLASS(BASE_TYPE), ALLOCATABLE :: POLY

ENUM, BIND(C)
    ENUMERATOR :: RED = 1, GREEN = 2, BLUE = 3
END ENUM

IF (ENDIF == 2) then
    ENDIF = 5
    ELSEIF = IF + 4*(ENDIF + &
                    2**10)
    ELSEIF (ENDIF == 3) THEN
    FUNCTION(IF) = ENDIF/ELSEIF
    PRINT *, ENDIF
ENDIF

ALLOCATE(ARR(N))
ARR = 0.0

ALLOCATE(TEST_TYPE :: POLY)

ASSOCIATE (TMP => ARR)
    TMP = 1.0
END ASSOCIATE

BLOCK
    INTEGER :: LOCAL
    LOCAL = 42
END BLOCK

CRITICAL
    PRINT *, "CRITICAL SECTION"
END CRITICAL

DO CONCURRENT (I = 1:N)
    ARR(I) = I
END DO

FORALL (J = 1:N)
    ARR(J) = ARR(J) * 2
END FORALL

WHERE (ARR > 2.0)
    ARR = ARR + 1.0
ELSEWHERE
    ARR = 0.0
END WHERE

SELECT CASE (N)
CASE (1)
    PRINT *, "ONE"
CASE DEFAULT
    PRINT *, "OTHER"
END SELECT

SELECT TYPE (POLY)
TYPE IS (TEST_TYPE)
    PRINT *, "TEST_TYPE"
CLASS DEFAULT
    PRINT *, "UNKNOWN"
END SELECT

IF (N > 0) THEN
    CALL TEST_PROC(I)
ELSE IF (N == 0) THEN
    STOP
ELSE
    ERROR STOP "NEGATIVE"
END IF

DO I = 1, N
    IF (I == 3) CYCLE
    IF (I == 4) EXIT
END DO

GOTO 100
GO TO 100
PRINT *, "SHOULD NOT PRINT"
100 CONTINUE

CALL C_F_POINTER(C_NULL_PTR, ARR)

SYNC ALL

OPEN(UNIT=10, FILE="test.txt", STATUS="UNKNOWN")
WRITE(10,*) "HELLO"
READ(10,*) STR
CLOSE(10)

INQUIRE(FILE="test.txt", EXIST=FLAG)

NULLIFY(POLY)

DEALLOCATE(ARR)

STOP
END PROGRAM KEYWORD_ZOO
